import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import { Send, User, Phone, MessageCircle, X, Search } from 'lucide-react';

const FRONTPAD_API = process.env.REACT_APP_FRONTPAD_API || 'http://localhost:3006';
const SITE_API = process.env.REACT_APP_SITE_API || 'http://localhost:3001';

const Messenger = () => {
  const [chats, setChats] = useState([]);
  const [selectedChat, setSelectedChat] = useState(null);
  const [messages, setMessages] = useState([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [sending, setSending] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const messagesEndRef = useRef(null);

  useEffect(() => {
    fetchChats();
  }, []);

  useEffect(() => {
    if (selectedChat) {
      fetchMessages(selectedChat.id);
    }
  }, [selectedChat]);

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const fetchChats = async () => {
    try {
      const response = await axios.get(`${SITE_API}/api/chats`);
      setChats(response.data || []);
    } catch (error) {
      console.error('Error fetching chats:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (customerId) => {
    try {
      const response = await axios.get(`${SITE_API}/api/messages/${customerId}`);
      setMessages(response.data || []);
    } catch (error) {
      console.error('Error fetching messages:', error);
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const sendMessage = async () => {
    if (!newMessage.trim() || !selectedChat) return;
    
    setSending(true);
    try {
      const formData = new FormData();
      formData.append('content', newMessage);
      formData.append('is_admin', 'true');
      formData.append('sender_id', selectedChat.id);

      await axios.post(`${SITE_API}/api/messages`, formData);
      setNewMessage('');
      fetchMessages(selectedChat.id);
      fetchChats(); // Обновить список чатов
    } catch (error) {
      console.error('Error sending message:', error);
      alert('Ошибка при отправке сообщения');
    } finally {
      setSending(false);
    }
  };

  const formatTime = (timestamp) => {
    const date = new Date(timestamp);
    return date.toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' });
  };

  const formatDate = (timestamp) => {
    const date = new Date(timestamp);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    if (date.toDateString() === today.toDateString()) {
      return 'Сегодня';
    } else if (date.toDateString() === yesterday.toDateString()) {
      return 'Вчера';
    }
    return date.toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit' });
  };

  const filteredChats = chats.filter(chat => 
    chat.name && chat.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  if (loading) {
    return (
      <div className="card" style={{ textAlign: 'center', padding: '40px' }}>
        Загрузка чатов...
      </div>
    );
  }

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 120px)', gap: '16px' }}>
      {/* Список чатов */}
      <div style={{ 
        width: '320px', 
        background: 'white', 
        borderRadius: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
        display: 'flex',
        flexDirection: 'column'
      }}>
        <div style={{ padding: '16px', borderBottom: '1px solid #e5e7eb' }}>
          <h2 style={{ fontSize: '20px', fontWeight: '600', marginBottom: '12px' }}>
            <MessageCircle size={20} style={{ marginRight: '8px', display: 'inline' }} />
            Сообщения
          </h2>
          <div style={{ position: 'relative' }}>
            <Search size={16} style={{ position: 'absolute', left: '10px', top: '50%', transform: 'translateY(-50%)', color: '#9ca3af' }} />
            <input
              type="text"
              className="form-input"
              placeholder="Поиск клиентов..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{ paddingLeft: '36px', fontSize: '14px' }}
            />
          </div>
        </div>

        <div style={{ flex: 1, overflowY: 'auto' }}>
          {filteredChats.length === 0 ? (
            <div style={{ textAlign: 'center', padding: '40px 20px', color: '#9ca3af' }}>
              Чатов пока нет
            </div>
          ) : (
            filteredChats.map(chat => (
              <div
                key={chat.id}
                onClick={() => setSelectedChat(chat)}
                style={{
                  padding: '12px 16px',
                  borderBottom: '1px solid #f3f4f6',
                  cursor: 'pointer',
                  background: selectedChat?.id === chat.id ? '#f0f9ff' : 'white',
                  transition: 'background 0.2s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.background = selectedChat?.id === chat.id ? '#f0f9ff' : '#f9fafb'}
                onMouseLeave={(e) => e.currentTarget.style.background = selectedChat?.id === chat.id ? '#f0f9ff' : 'white'}
              >
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <div style={{ 
                    width: '44px', 
                    height: '44px', 
                    borderRadius: '50%', 
                    background: '#e0e7ff',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center'
                  }}>
                    <User size={20} color="#4338ca" />
                  </div>
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontWeight: '500', fontSize: '14px', marginBottom: '2px' }}>
                      {chat.name || 'Клиент'}
                    </div>
                    <div style={{ fontSize: '12px', color: '#6b7280', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                      {chat.last_message || 'Нет сообщений'}
                    </div>
                  </div>
                  {chat.last_message_time && (
                    <div style={{ fontSize: '11px', color: '#9ca3af' }}>
                      {formatTime(chat.last_message_time)}
                    </div>
                  )}
                </div>
              </div>
            ))
          )}
        </div>
      </div>

      {/* Окно чата */}
      {selectedChat ? (
        <div style={{ 
          flex: 1, 
          background: 'white', 
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
          display: 'flex',
          flexDirection: 'column'
        }}>
          {/* Заголовок */}
          <div style={{ 
            padding: '16px 20px', 
            borderBottom: '1px solid #e5e7eb',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between'
          }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <div style={{ 
                width: '40px', 
                height: '40px', 
                borderRadius: '50%', 
                background: '#e0e7ff',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}>
                <User size={18} color="#4338ca" />
              </div>
              <div>
                <div style={{ fontWeight: '600', fontSize: '16px' }}>
                  {selectedChat.name || 'Клиент'}
                </div>
                {selectedChat.email && (
                  <div style={{ fontSize: '12px', color: '#6b7280' }}>
                    {selectedChat.email}
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Сообщения */}
          <div style={{ flex: 1, overflowY: 'auto', padding: '20px', background: '#f9fafb' }}>
            {messages.length === 0 ? (
              <div style={{ textAlign: 'center', color: '#9ca3af', marginTop: '40px' }}>
                Нет сообщений
              </div>
            ) : (
              messages.map((msg, idx) => {
                const showDate = idx === 0 || formatDate(messages[idx - 1].timestamp) !== formatDate(msg.timestamp);
                const isAdmin = msg.is_admin === 1 || msg.is_admin === true;

                return (
                  <React.Fragment key={msg.id}>
                    {showDate && (
                      <div style={{ textAlign: 'center', margin: '16px 0', fontSize: '12px', color: '#9ca3af' }}>
                        {formatDate(msg.timestamp)}
                      </div>
                    )}
                    <div style={{ 
                      display: 'flex', 
                      justifyContent: isAdmin ? 'flex-end' : 'flex-start',
                      marginBottom: '8px'
                    }}>
                      {!isAdmin && (
                        <div style={{ 
                          width: '28px', 
                          height: '28px', 
                          borderRadius: '50%', 
                          background: '#e5e7eb',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          marginRight: '8px',
                          marginTop: '4px'
                        }}>
                          <User size={14} color="#6b7280" />
                        </div>
                      )}
                      <div style={{ 
                        maxWidth: '70%',
                        padding: '10px 14px',
                        borderRadius: isAdmin ? '16px 16px 4px 16px' : '16px 16px 16px 4px',
                        background: isAdmin ? '#3b82f6' : 'white',
                        color: isAdmin ? 'white' : '#374151',
                        boxShadow: '0 1px 2px rgba(0,0,0,0.05)'
                      }}>
                        {msg.image_url && (
                          <img 
                            src={`${SITE_API}/uploads/${msg.image_url}`}
                            alt="Вложение"
                            style={{ maxWidth: '100%', borderRadius: '8px', marginBottom: '8px' }}
                          />
                        )}
                        {msg.cart_data && (
                          <div style={{ 
                            background: isAdmin ? '#2563eb' : '#fef3c7',
                            padding: '10px',
                            borderRadius: '8px',
                            marginBottom: '8px',
                            fontSize: '13px'
                          }}>
                            <div style={{ fontWeight: '600', marginBottom: '4px' }}>
                              🛒 Корзина
                            </div>
                            {JSON.parse(msg.cart_data).map((item, i) => (
                              <div key={i} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2px' }}>
                                <span>{item.name} ×{item.quantity}</span>
                                <span>{item.price * item.quantity} ₽</span>
                              </div>
                            ))}
                            <div style={{ fontWeight: '600', marginTop: '8px', paddingTop: '8px', borderTop: '1px solid rgba(0,0,0,0.1)' }}>
                              Итого: {msg.cart_total} ₽
                            </div>
                          </div>
                        )}
                        {msg.content && (
                          <div style={{ fontSize: '14px', lineHeight: '1.4' }}>
                            {msg.content}
                          </div>
                        )}
                        <div style={{ 
                          fontSize: '10px', 
                          marginTop: '4px',
                          opacity: 0.7,
                          textAlign: 'right'
                        }}>
                          {formatTime(msg.timestamp)}
                        </div>
                      </div>
                      {isAdmin && (
                        <div style={{ 
                          width: '28px', 
                          height: '28px', 
                          borderRadius: '50%', 
                          background: '#3b82f6',
                          display: 'flex',
                          alignItems: 'center',
                          justifyContent: 'center',
                          marginLeft: '8px',
                          marginTop: '4px'
                        }}>
                          <span style={{ color: 'white', fontSize: '12px' }}>A</span>
                        </div>
                      )}
                    </div>
                  </React.Fragment>
                );
              })
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Поле ввода */}
          <div style={{ 
            padding: '16px 20px', 
            borderTop: '1px solid #e5e7eb',
            display: 'flex',
            gap: '12px'
          }}>
            <input
              type="text"
              className="form-input"
              placeholder="Введите сообщение..."
              value={newMessage}
              onChange={(e) => setNewMessage(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && sendMessage()}
              style={{ flex: 1 }}
            />
            <button
              className="btn btn-primary"
              onClick={sendMessage}
              disabled={sending || !newMessage.trim()}
              style={{ padding: '10px 20px' }}
            >
              <Send size={18} />
            </button>
          </div>
        </div>
      ) : (
        <div style={{ 
          flex: 1, 
          background: 'white', 
          borderRadius: '12px',
          boxShadow: '0 2px 8px rgba(0,0,0,0.08)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          color: '#9ca3af'
        }}>
          <div style={{ textAlign: 'center' }}>
            <MessageCircle size={48} style={{ marginBottom: '16px', opacity: 0.5 }} />
            <div>Выберите чат для просмотра переписки</div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Messenger;
